// Complex state machine that .holo references
import { State, Transition } from "@holoscript/std";
import type { NPC, DialogueNode } from "./types";

interface DialogueState {
  currentNode: string;
  history: string[];
  flags: Map<string, boolean>;
}

export system DialogueSystem {
  private state: DialogueState = {
    currentNode: "root",
    history: [],
    flags: new Map()
  };

  private trees: Map<string, DialogueNode[]> = new Map();

  async start(treeId: string): Promise<void> {
    const tree = await this.loadTree(treeId);
    this.state.currentNode = "root";
    this.state.history = [];

    await this.showNode(tree.root);
  }

  private async showNode(node: DialogueNode): Promise<void> {
    // Display the dialogue
    UI.showDialogue({
      speaker: node.speaker,
      text: node.text,
      choices: this.filterChoices(node.choices)
    });

    // Wait for player choice
    const choice = await UI.waitForChoice();

    // Process the choice
    await this.processChoice(choice);
  }

  private filterChoices(choices: Choice[]): Choice[] {
    // Complex logic: filter based on flags, inventory, reputation
    return choices.filter(c => {
      if (c.requires?.flag && !this.state.flags.get(c.requires.flag)) {
        return false;
      }
      if (c.requires?.item && !Player.hasItem(c.requires.item)) {
        return false;
      }
      return true;
    });
  }

  // ... more complex logic
}
```

**combat.hsplus - Heavy math:**
```hsplus
import { Vec3, clamp, lerp } from "@holoscript/std";

export system CombatSystem {
  calculateDamage(attacker: Entity, defender: Entity, weapon: Weapon): number {
    // Complex formula with many factors
    const baseDamage = weapon.damage * attacker.stats.strength;
    const critChance = attacker.stats.luck / 100;
    const isCrit = Math.random() < critChance;
    const critMultiplier = isCrit ? 2.0 : 1.0;

    const defense = defender.stats.defense;
    const armorReduction = 1 - (defense / (defense + 100));

    const elementalBonus = this.getElementalMultiplier(
      weapon.element, 
      defender.resistances
    );

    const finalDamage = Math.floor(
      baseDamage * critMultiplier * armorReduction * elementalBonus
    );

    return clamp(finalDamage, 1, 9999);
  }

  // This would be awful to write in .holo
  getElementalMultiplier(element: Element, resistances: Resistances): number {
    const resist = resistances[element] ?? 0;
    if (resist > 100) return 0;  // Immune
    if (resist > 0) return 1 - (resist / 100);  // Resistant
    if (resist < 0) return 1 + (Math.abs(resist) / 100);  // Weak
    return 1;  // Neutral
  }
}
```

