composition "Switch Puzzle" {

  // The switches (input nodes)
  orb Switch1 {
    position: [-2, 1, 0]
    state: "off"
    traits: ["interactive", "toggle"]
  }

  orb Switch2 {
    position: [0, 1, 0]
    state: "off"
    traits: ["interactive", "toggle"]
  }

  orb Switch3 {
    position: [2, 1, 0]
    state: "off"
    traits: ["interactive", "toggle"]
  }

  // The door (output node)
  orb Door {
    position: [0, 0, 5]
    state: "locked"
    traits: ["door"]
  }

  logic {
    // Each switch toggles and checks the puzzle
    on_interact("Switch1") {
      Switch1.state = toggle(Switch1.state)
      Switch1.play_sound(Switch1.state)
      check_puzzle()
    }

    on_interact("Switch2") {
      Switch2.state = toggle(Switch2.state)
      Switch2.play_sound(Switch2.state)
      check_puzzle()
    }

    on_interact("Switch3") {
      Switch3.state = toggle(Switch3.state)
      Switch3.play_sound(Switch3.state)
      check_puzzle()
    }

    // The convergence point
    function check_puzzle() {
      if (Switch1.state == "on" && 
          Switch2.state == "on" && 
          Switch3.state == "on") {
