[Enemy]     [Sword]     [on_attack]
   ○           ○             ?
 health      damage      trigger from where?
```

**Three issues:**

1. **`on_attack()` has no source** - Who/what triggers the attack? The event is floating with no connection.

2. **Sword is an orb, not equipped** - It's just sitting in the world. There's no connection showing the player USING the sword.

3. **No player node** - Who's attacking? The flow is:
   ```
   [???] ──attack──→ [Enemy]
   ```
   The source is missing!

**Fixed version:**

```holo
composition "Fixed Combat" {
  // The player (the attacker)
  orb Player {
    position: [0, 0, -5]
    equipped_weapon: "Sword"  // Connection to sword
  }

  // The enemy (the target)  
  orb Enemy { 
    position: [0, 0, 0]
    health: 100
    traits: ["attackable"]  // Can receive attacks
  }

  // The weapon (a data node, or could be equippable item)
  orb Sword { 
    position: [2, 0, 0]
    damage: 25
    traits: ["weapon", "pickupable"]
  }

  logic {
    // Pickup flow: Player → Sword
    on_interact("Sword") {
      Player.equipped_weapon = Sword
      Sword.visible = false  // Now "held"
      ui.toast("Equipped Sword!")
    }

    // Attack flow: Player → Enemy (using equipped weapon)
    on_player_attack(target) {
      if (target.traits.includes("attackable") && Player.equipped_weapon) {
        let damage = Player.equipped_weapon.damage
        target.health -= damage

        ui.show_damage(damage, target.position)
        audio.play("sword_hit")

        if (target.health <= 0) {
          emit("enemy_died", target)
        }
      }
    }
  }
}
```

**Now the graph is complete:**
```
[Player] ──equips──→ [Sword]
    │                   │
    │                damage: 25
    │                   │
    └──attacks with────→│
                        ↓
                    [Enemy]
                    health -= 25
```

Every action has a source, every effect has a target, and all the connections are explicit!

Save/Load is about **serializing the graph state** and restoring it:

```
SAVE:                              LOAD:
[Game State Graph]                 [Save File]
        │                               │
   serialize                       deserialize
        │                               │
        ↓                               ↓
   [Save File]                  [Game State Graph]
                                (restored exactly)
```

**What to save:**
```
[Save Data]
├── Player
│   ├── position: [x, y, z]
│   ├── health: 85
│   ├── inventory: [...]
│   └── quests: {...}
│
├── World State
│   ├── opened_chests: ["chest_1", "chest_5"]
│   ├── killed_enemies: ["goblin_3"]
│   └── unlocked_doors: ["door_east"]
│
└── NPCs
    ├── merchant: { dialogue_state: "introduced" }
    └── guard: { quest_given: true }
```

```holo
composition "Save System" {

  // Save data structure
  const SaveManager = {
    current_slot: null,

    // Collect all saveable state
    gather_save_data() {
      return {
        version: "1.0",
        timestamp: Date.now(),

        player: {
          position: Player.position,
          rotation: Player.rotation,
          health: Player.health,
          max_health: Player.max_health,
          gold: Player.gold,
          inventory: this.serialize_inventory(),
          equipped: Player.equipped,
          stats: Player.stats
        },

        world: {
          current_scene: Scene.current.id,
          time_of_day: World.time,
          weather: World.weather,

          // Track modified objects
          opened_containers: this.get_opened_containers(),
          destroyed_objects: this.get_destroyed(),
          unlocked_doors: this.get_unlocked_doors(),
          activated_triggers: this.get_activated_triggers()
        },

        quests: {
          active: Quest.get_active_quests(),
          completed: Quest.get_completed_quests(),
          progress: Quest.get_all_progress()
        },

        npcs: this.serialize_npc_states()
      }
    },

    // Restore state from save
    apply_save_data(data) {
      // Player
      Player.position = data.player.position
      Player.rotation = data.player.rotation
      Player.health = data.player.health
      Player.gold = data.player.gold
      this.restore_inventory(data.player.inventory)

      // World
      Scene.load(data.world.current_scene)
      World.time = data.world.time_of_day
      World.weather = data.world.weather

      // Restore object states
      for (id in data.world.opened_containers) {
        let obj = Scene.find(id)
        if (obj) obj.opened = true
      }
      for (id in data.world.destroyed_objects) {
        let obj = Scene.find(id)
        if (obj) obj.destroy()
      }
      for (id in data.world.unlocked_doors) {
        let obj = Scene.find(id)
        if (obj) obj.unlock()
      }

      // Quests
      Quest.restore_state(data.quests)

      // NPCs
      this.restore_npc_states(data.npcs)
    },

    serialize_inventory() {
      let items = []
      for (slot in PlayerInventory) {
        if (slot.item) {
          items.push({
            slot_index: slot.index,
            item_id: slot.item.id,
            count: slot.count
          })
        }
      }
      return items
    },

    serialize_npc_states() {
      let states = {}
      for (npc in NPCs) {
        states[npc.id] = {
          dialogue_progress: npc.dialogue_progress,
          reputation: npc.reputation,
          quest_flags: npc.quest_flags,
          shop_inventory: npc.shop_inventory
        }
      }
      return states
    }
  }

  logic {
    // Save key
    on_key("F5") {
      let data = SaveManager.gather_save_data()
      Storage.save("slot_" + SaveManager.current_slot, data)
      ui.toast("Game Saved")
    }

    // Load key
    on_key("F9") {
      let data = Storage.load("slot_" + SaveManager.current_slot)
      if (data) {
        SaveManager.apply_save_data(data)
        ui.toast("Game Loaded")
      } else {
        ui.toast("No save found")
      }
    }

    // Save menu UI
    on_open_save_menu() {
      let slots = []
      for (i = 0; i < 5; i++) {
        let data = Storage.load("slot_" + i)
        slots.push({
          index: i,
          empty: data == null,
          timestamp: data?.timestamp,
          player_name: data?.player?.name,
          play_time: data?.play_time
        })
      }
      SaveUI.show(slots)
    }

    // Autosave
    every(300000) {  // Every 5 minutes
      let data = SaveManager.gather_save_data()
      Storage.save("autosave", data)
    }

    // Autosave on important events
    on_quest_complete(quest) {
      let data = SaveManager.gather_save_data()
      Storage.save("autosave", data)
    }
  }
}
```

**The save/load flow:**
```
SAVE:
[Player] ──serialize──┐
[World]  ──serialize──┼──→ [JSON] ──→ [Storage]
[Quests] ──serialize──┤
[NPCs]   ──serialize──┘

LOAD:
[Storage] ──→ [JSON] ──parse──→ [Data]
                                  │
              ┌───────────────────┼───────────────────┐
              ↓                   ↓                   ↓
         [Player]            [World]            [Quests]
        restored!           restored!          restored!
```

The key is capturing ALL the edges that changed (opened chests, killed enemies) not just node positions.

Checkpoints are a **sequential flow with validation**:

```
[Start] ──→ [CP1] ──→ [CP2] ──→ [CP3] ──→ [Finish]
              │         │         │          │
           passed?   passed?   passed?    all passed?
              │         │         │          │
              ↓         ↓         ↓          ↓
           valid     valid     valid      COMPLETE!
```

**Key rule:** Must pass checkpoints IN ORDER. Can't skip!

```holo
composition "Racing Checkpoints" {

  template "Checkpoint" {
    state {
      index: 0
      passed: false
      pass_time: null
    }

    action try_pass(racer) {
      // Already passed?
      if (this.passed) return

      // Check if previous checkpoint was passed
      if (this.index > 0) {
        let prev = Checkpoints[this.index - 1]
        if (!prev.passed) {
          // Missed a checkpoint!
          ui.toast("Missed checkpoint " + this.index + "!", "warning")
          return
        }
      }

      // Valid pass!
      this.passed = true
      this.pass_time = Race.time

      audio.play("checkpoint_ding")
      this.flash_green()

      emit("checkpoint_passed", { checkpoint: this, racer: racer })
    }
  }

  spatial_group "Track" {
    // Start line
    orb StartLine {
      position: [0, 0, 0]
      width: 10
      traits: ["start_trigger"]
    }

    // Checkpoints around the track
    object "CP_1" using "Checkpoint" {
      position: [50, 0, 20]
      index: 0
      rotation: [0, 45, 0]
    }

    object "CP_2" using "Checkpoint" {
      position: [80, 0, 60]
      index: 1
      rotation: [0, 90, 0]
    }

    object "CP_3" using "Checkpoint" {
      position: [50, 0, 100]
      index: 2
      rotation: [0, 135, 0]
    }

    object "CP_4" using "Checkpoint" {
      position: [0, 0, 80]
      index: 3
      rotation: [0, 180, 0]
    }

    // Finish line (same as start for circuits)
    orb FinishLine {
      position: [0, 0, 0]
      width: 10
      traits: ["finish_trigger"]
    }
  }

  // Race state
  const Race = {
    state: "waiting",  // waiting, countdown, racing, finished
    time: 0,
    lap: 0,
    max_laps: 3,
    best_lap: null,
    checkpoint_count: 4
  }

  logic {
    // Countdown sequence
    on_race_start() {
      Race.state = "countdown"

      after(1000) { ui.show_big("3") }
      after(2000) { ui.show_big("2") }
      after(3000) { ui.show_big("1") }
      after(4000) {
        ui.show_big("GO!")
        Race.state = "racing"
        Race.time = 0
      }
    }

    // Race timer
    every(10) {
      if (Race.state == "racing") {
        Race.time += 0.01
        ui.update_timer(Race.time)
      }
    }

    // Checkpoint trigger detection
    on_enter_trigger(trigger, racer) {
      if (trigger.traits.includes("Checkpoint")) {
        trigger.try_pass(racer)
      }
    }

    // Track checkpoint progress
    on_event("checkpoint_passed", data) {
      let passed_count = count_passed_checkpoints()
      ui.update_checkpoint_counter(passed_count, Race.checkpoint_count)
    }

    // Finish line logic
    on_enter_trigger("FinishLine", racer) {
      // Check all checkpoints passed
      let all_passed = true
      for (cp in Checkpoints) {
        if (!cp.passed) {
          all_passed = false
          break
        }
      }

      if (!all_passed) {
        ui.toast("Complete all checkpoints first!")
        return
      }

      // Lap complete!
      Race.lap += 1
      let lap_time = Race.time

      if (!Race.best_lap || lap_time < Race.best_lap) {
        Race.best_lap = lap_time
        ui.toast("New best lap: " + format_time(lap_time))
      }

      if (Race.lap >= Race.max_laps) {
        // Race finished!
        Race.state = "finished"
        ui.show_results({
          total_time: Race.time,
          best_lap: Race.best_lap,
          position: calculate_position()
        })
      } else {
        // Reset checkpoints for next lap
        for (cp in Checkpoints) {
          cp.passed = false
        }
        ui.toast("Lap " + Race.lap + " / " + Race.max_laps)
      }
    }
  }
}
```

