  on_click("btn4") { C.do(); D.do(); E.do(); }
}

**Spaghetti Analysis:**

Current mess:
```
[btn1] ──→ A, B, C, (D?)
[btn2] ──→ B, C, E
[btn3] ──→ A, C, (F|G)
[btn4] ──→ C, D, E
```

**Problems:**
1. **C.do() is called by ALL buttons** - hidden coupling
2. **Duplicated calls** - B appears in btn1 and btn2
3. **Mixed concerns** - buttons know about all the things they affect
4. **Hard to modify** - adding new behavior requires editing multiple handlers

**Pattern detected:** Implicit event bus with scattered handlers

**Refactored architecture:**

```
              [Button Clicked]
                    │
               emit event
                    │
     ┌──────────────┼──────────────┐
     │              │              │
     ↓              ↓              ↓
 [Handler A]   [Handler C]    [Handler E]
 listens for   listens for    listens for
  btn1, btn3    ALL buttons    btn2, btn4
```

**Refactored code:**

```holo
// Separate concerns - each system handles its own events

// System A - responds to specific buttons
system A_Handler {
  init() {
    listen("btn1", "btn3")
  }

  on_trigger() {
    A.do()
  }
}

// System B - responds to btn1, btn2
system B_Handler {
  init() {
    listen("btn1", "btn2")
  }

  on_trigger() {
    B.do()
  }
}

// System C - responds to ALL (it's a common dependency)
system C_Handler {
  on_any_button() {
    C.do()
  }
}

// System D - conditional on btn1, btn4
system D_Handler {
  on_trigger(source) {
    if (source == "btn1" && x) {
      D.do()
    } else if (source == "btn4") {
      D.do()
    }
  }
}

// System E - btn2, btn4
system E_Handler {
  init() {
    listen("btn2", "btn4")
  }

  on_trigger() {
    E.do()
  }
}

// System F/G - btn3 with condition
system FG_Handler {
  init() {
    listen("btn3")
  }

  on_trigger() {
    if (y) F.do()
    else G.do()
  }
}

// Clean button handlers - just emit events
logic {
  on_click("btn1") { emit("btn1") }
  on_click("btn2") { emit("btn2") }
  on_click("btn3") { emit("btn3") }
  on_click("btn4") { emit("btn4") }
}
```

**Even simpler - data-driven:**

```holo
const ButtonActions = {
  "btn1": { always: ["A", "B", "C"], conditional: { x: ["D"] } },
  "btn2": { always: ["B", "C", "E"] },
  "btn3": { always: ["A", "C"], conditional: { y: ["F"], "!y": ["G"] } },
  "btn4": { always: ["C", "D", "E"] }
}

logic {
  on_click(button_id) {
    let config = ButtonActions[button_id]

    // Always actions
    for (action in config.always) {
      Systems[action].do()
    }

    // Conditional actions
    for (condition, actions in config.conditional) {
      if (evaluate(condition)) {
        for (action in actions) {
          Systems[action].do()
        }
      }
    }
  }
}
```

**The clean graph:**
```
[ButtonActions Config]
         │
    defines what
         │
         ↓
   [Click Handler]
         │
    reads config
         │
         ↓
   [Execute Actions]
      /  |  |  \
     A   B  C   D...
```

**Benefits:**
- Add new button = add config entry
- Change what C does = edit one place
- Clear separation of "what triggers" vs "what happens"

**Modular Ability Architecture:**

The key is **composition over inheritance** - abilities are built from reusable components:

```
              [Ability]
                 │
    ┌────────────┼────────────┐
    │            │            │
[Targeting]  [Effects]    [Costs]
    │            │            │
┌───┴───┐   ┌───┴───┐   ┌───┴───┐
│       │   │       │   │       │
Self   AOE  Damage Buff  Mana  Cooldown
Target Cone  Heal  Debuff Stamina
Ground Line  Summon       Health
```

**Component-based design:**

```holo
// === TARGETING COMPONENTS ===
const Targeting = {
  self: {
    get_targets: () => [Caster]
  },
  single_enemy: {
    range: 10,
    get_targets: () => [get_target_enemy(Caster, this.range)]
  },
  aoe_around_self: {
    radius: 5,
    get_targets: () => get_enemies_in_radius(Caster.position, this.radius)
  },
  aoe_at_point: {
    radius: 5,
    range: 15,
    get_targets: (point) => get_enemies_in_radius(point, this.radius)
  },
  cone: {
    angle: 60,
    range: 8,
    get_targets: () => get_enemies_in_cone(Caster, this.angle, this.range)
  },
  line: {
    width: 2,
    range: 20,
    get_targets: () => get_enemies_in_line(Caster, this.width, this.range)
  }
}

// === EFFECT COMPONENTS ===
const Effects = {
  damage: {
    apply: (targets, amount, type) => {
      for (t in targets) {
        t.take_damage(amount, type)
      }
    }
  },
  heal: {
    apply: (targets, amount) => {
      for (t in targets) {
        t.heal(amount)
      }
    }
  },
  buff: {
    apply: (targets, stat, amount, duration) => {
      for (t in targets) {
        t.add_buff(stat, amount, duration)
      }
    }
  },
  debuff: {
    apply: (targets, stat, amount, duration) => {
      for (t in targets) {
        t.add_debuff(stat, amount, duration)
      }
    }
  },
  dot: {
    apply: (targets, damage, interval, duration) => {
      for (t in targets) {
        t.add_dot(damage, interval, duration)
      }
    }
  },
  knockback: {
    apply: (targets, force) => {
      for (t in targets) {
        let dir = (t.position - Caster.position).normalized
        t.apply_force(dir * force)
      }
    }
  },
  summon: {
    apply: (position, creature, count, duration) => {
      for (i = 0; i < count; i++) {
        let pos = position + random_offset(2)
        spawn(creature, pos, { owner: Caster, lifetime: duration })
      }
    }
  }
}

// === COST COMPONENTS ===
const Costs = {
  mana: {
    amount: 0,
    can_afford: () => Caster.mana >= this.amount,
    pay: () => Caster.mana -= this.amount
  },
  health: {
    amount: 0,
    can_afford: () => Caster.health > this.amount,
    pay: () => Caster.health -= this.amount
  },
  cooldown: {
    duration: 0,
    ready_at: 0,
    can_afford: () => Time.now >= this.ready_at,
    pay: () => this.ready_at = Time.now + this.duration
  },
  charges: {
    max: 3,
    current: 3,
    recharge_time: 10,
    can_afford: () => this.current > 0,
    pay: () => {
      this.current -= 1
      if (this.current < this.max) {
        after(this.recharge_time * 1000) {
          this.current = min(this.current + 1, this.max)
        }
      }
    }
  }
}

// === ABILITY TEMPLATE ===
template "Ability" {
  state {
    name: ""
    targeting: null
    effects: []
    costs: []
    cast_time: 0
    animation: ""
    sound: ""
    particles: ""
  }

  action can_use() {
    for (cost in this.costs) {
      if (!cost.can_afford()) return false
    }
    return true
  }

  action use(target_point = null) {
    if (!this.can_use()) return false

    // Pay costs
    for (cost in this.costs) {
      cost.pay()
    }

    // Get targets
    let targets = this.targeting.get_targets(target_point)

    // Cast time (if any)
    if (this.cast_time > 0) {
      Caster.start_cast(this.cast_time)
      after(this.cast_time * 1000) {
        this.execute(targets)
      }
    } else {
      this.execute(targets)
    }

    return true
  }

  action execute(targets) {
    // Visual/audio
    Caster.play_animation(this.animation)
    audio.play(this.sound)
    particles.spawn(this.particles, Caster.position)

    // Apply effects
    for (effect in this.effects) {
      effect.apply(targets)
    }
  }
}

// === EXAMPLE ABILITIES ===

// Fireball: Single target, damage + DOT
object "Fireball" using "Ability" {
  name: "Fireball"
  targeting: Targeting.single_enemy with { range: 15 }
  effects: [
    Effects.damage with { amount: 50, type: "fire" },
    Effects.dot with { damage: 10, interval: 1, duration: 5 }
  ]
  costs: [
    Costs.mana with { amount: 30 },
    Costs.cooldown with { duration: 3 }
