3. **Multi-sensory scare** (visual + audio + camera)
4. **Cooldown** (don't spam scares)

Here's a reusable scare system:

```holo
composition "Horror Scene" {

  // Creepy atmosphere
  environment {
    lighting: {
      ambient: { color: "#1a1a2e", intensity: 0.1 }
      fog: { color: "#000", density: 0.5 }
    }
    audio: {
      ambient: "creepy_drone"
      volume: 0.3
    }
  }

  template "JumpScare" {
    state {
      triggered: false
      cooldown: 30  // Can't trigger again for 30 seconds
    }

    action trigger() {
      if (this.triggered) return
      this.triggered = true

      // THE SCARE
      audio.play(this.sound, { volume: 1.0 })
      camera.shake(0.8, 0.5)

      if (this.monster) {
        this.monster.visible = true
        this.monster.lunge_at(Player)
      }

      // Screen effects
      post_process.flash_white(100)
      post_process.chromatic_aberration(0.5, 300)

      // Flicker lights
      for (light in nearby_lights(this.position, 10)) {
        light.flicker(500, 3)
      }

      // Reset after cooldown
      after(this.cooldown * 1000) {
        this.triggered = false
        if (this.monster) this.monster.visible = false
      }
    }
  }

  spatial_group "Hallway" {
    // Invisible trigger zone
    object "Scare_1" using "JumpScare" {
      position: [10, 0, 0]
      trigger_radius: 2
      sound: "scream_demonic"
      monster: "ghost_girl"
      traits: ["invisible", "trigger_zone"]
    }

    // The monster (hidden until triggered)
    orb GhostGirl {
      position: [10, 0, 3]
      visible: false
      model: "ghost_child"
      material: { opacity: 0.7, emissive: "#aaaaff" }
    }

    // Flickering lights for atmosphere
    orb Light_1 {
      position: [5, 3, 0]
      type: "point"
      color: "#ffaa66"
      intensity: 0.5
      flicker_chance: 0.05
    }
  }

  logic {
    // Trigger on proximity
    on_player_enter_radius(scare, radius) where scare is JumpScare {
      scare.trigger()
    }

    // Random ambient scares
    every(random(15000, 45000)) {
      let scares = [
        () => audio.play_distant("footsteps"),
        () => audio.play_distant("whisper"),
        () => random_light().flicker(200, 1),
        () => audio.play("door_creak", { volume: 0.3 })
      ]
      random_choice(scares)()
    }
  }
}
```

**Pro horror tips:**
- Less is more - anticipation > constant scares
- Sound design is 80% of horror
- Give player a false sense of safety, THEN scare
- Vary timing - unpredictability is scarier

