Minimaps show a **top-down view of your world graph**:

```
[World]                    [Minimap]
                           ┌─────────┐
[Player] ●                 │    ●    │ ← Player dot
[Enemy]  ○                 │  ○   ○  │ ← Enemy dots
[NPC]    ◇                 │    ◇    │ ← NPC dots
[Quest]  ★                 │ ★       │ ← Quest marker
                           └─────────┘
```

Here's how to build it:

```holo
composition "Minimap System" {

  // Minimap UI element (top-right corner)
  ui MinimapPanel {
    position: { right: 20, top: 20 }
    size: { width: 200, height: 200 }
    background: "rgba(0, 0, 0, 0.5)"
    border_radius: 100  // Circular minimap
    mask: "circle"
  }

  // Minimap configuration
  const MinimapConfig = {
    scale: 0.1,           // World units to minimap pixels
    rotation: "player",   // Rotate with player or fixed north
    range: 100,           // How far to show
    icons: {
      player: { shape: "triangle", color: "#00ff00", size: 8 },
      enemy: { shape: "circle", color: "#ff0000", size: 5 },
      npc: { shape: "diamond", color: "#00ffff", size: 6 },
      quest: { shape: "star", color: "#ffff00", size: 7 },
      poi: { shape: "square", color: "#ffffff", size: 4 }
    }
  }

  // Minimap renderer
  system MinimapRenderer {
    update() {
      MinimapPanel.clear()

      let center = MinimapPanel.center
      let player_pos = Player.position
      let player_rot = Player.rotation.y

      // Draw terrain/background (optional)
      this.draw_terrain(player_pos)

      // Draw tracked objects
      this.draw_markers(player_pos, player_rot)

      // Draw player in center
      this.draw_icon(center, MinimapConfig.icons.player, player_rot)
    }

    draw_markers(player_pos, player_rot) {
      // Enemies
      for (enemy in Enemies) {
        let offset = this.world_to_minimap(enemy.position, player_pos, player_rot)
        if (offset.in_range) {
          this.draw_icon(offset.pos, MinimapConfig.icons.enemy)
        }
      }

      // NPCs
      for (npc in NPCs) {
        let offset = this.world_to_minimap(npc.position, player_pos, player_rot)
        if (offset.in_range) {
          let icon = npc.has_quest ? MinimapConfig.icons.quest : MinimapConfig.icons.npc
          this.draw_icon(offset.pos, icon)
        }
      }

      // Quest objectives
      for (quest in Player.active_quests) {
        if (quest.marker_position) {
          let offset = this.world_to_minimap(quest.marker_position, player_pos, player_rot)
          // Show even if out of range (edge of minimap)
          this.draw_icon(offset.pos_clamped, MinimapConfig.icons.quest)
        }
      }
    }

    world_to_minimap(world_pos, player_pos, player_rot) {
      // Offset from player
      let dx = world_pos.x - player_pos.x
      let dz = world_pos.z - player_pos.z

      // Rotate if minimap rotates with player
      if (MinimapConfig.rotation == "player") {
        let cos = Math.cos(-player_rot)
        let sin = Math.sin(-player_rot)
        let rx = dx * cos - dz * sin
        let rz = dx * sin + dz * cos
        dx = rx
        dz = rz
      }

      // Scale to minimap
      let mx = MinimapPanel.center.x + dx * MinimapConfig.scale
      let my = MinimapPanel.center.y + dz * MinimapConfig.scale

      // Check range
      let dist = Math.sqrt(dx*dx + dz*dz)
      let in_range = dist < MinimapConfig.range

      // Clamp to edge for out-of-range markers
      let pos_clamped = { x: mx, y: my }
      if (!in_range) {
        let angle = Math.atan2(dz, dx)
        let edge_dist = MinimapPanel.size.width / 2 - 10
        pos_clamped.x = MinimapPanel.center.x + Math.cos(angle) * edge_dist
        pos_clamped.y = MinimapPanel.center.y + Math.sin(angle) * edge_dist
      }

      return { pos: { x: mx, y: my }, pos_clamped, in_range }
    }
  }

  logic {
    // Update minimap every frame
    every(50) {
      MinimapRenderer.update()
    }

    // Toggle minimap size on M key
    on_key("M") {
      if (MinimapPanel.size.width == 200) {
        MinimapPanel.animate_to({ size: { width: 400, height: 400 } }, 200)
      } else {
        MinimapPanel.animate_to({ size: { width: 200, height: 200 } }, 200)
      }
    }
  }
}
```

**The flow:**
```
[World Objects]                [Minimap]
      │                            │
  positions                    rendering
      │                            │
      ↓                            ↓
[world_to_minimap] ──transform──→ [draw_icon]
      │                            │
 - offset from player             - shape
 - rotate                         - color
 - scale                          - position
```

