    count: 100
    emit_mode: "burst"  // All at once

    color: {
      start: "#ffffff",
      mid: "#ffaa00",
      end: "#ff3300"
    }
    opacity: { start: 1, end: 0 }

    size: { start: 0.5, end: 2 }  // Grow!

    lifetime: { min: 0.3, max: 0.8 }

    speed: { min: 5, max: 15 }
    direction: { base: "outward", spread: 180 }  // All directions

    gravity: 2  // Falls down after burst

    blend_mode: "additive"
  }

  // Sparkle/magic dust
  particle MagicDust {
    count: 30
    emit_rate: 20

    color: ["#66ffff", "#ff66ff", "#ffff66"]  // Random from list
    opacity: { start: 0, peak: 1, end: 0 }  // Fade in AND out

    size: { start: 0.1, end: 0.05 }

    lifetime: { min: 1, max: 2 }

    speed: { min: 0.2, max: 0.5 }
    direction: { base: "random" }

    // Twinkle effect
    flicker: { 
      enabled: true,
      frequency: 5,
      intensity: 0.5
    }

    blend_mode: "additive"
    texture: "star_4point"
  }

  // Smoke
  particle Smoke {
    count: 20
    emit_rate: 10

    color: { start: "#666666", end: "#333333" }
    opacity: { start: 0.6, end: 0 }

    size: { start: 0.3, end: 2 }  // Expands

    lifetime: { min: 2, max: 4 }

    speed: { min: 0.5, max: 1 }
