Vehicles transform player movement into **mounted state** with different physics:

```
[Player on foot]                 [Player in vehicle]
      │                                 │
   walk/run                          drive
   jump                              accelerate
   interact                          steer/brake
      │                                 │
      └──── enter vehicle ────→        │
           ←── exit vehicle ───────────┘
```

**Vehicle system:**

```holo
composition "Vehicle System" {

  template "Vehicle" {
    state {
      // Vehicle properties
      type: "car"           // car, bike, boat, plane
      max_speed: 30
      acceleration: 5
      brake_power: 10
      turn_speed: 90        // degrees per second

      // Current state
      speed: 0
      driver: null
      fuel: 100
      health: 100
    }

    action enter(player) {
      if (this.driver) return false  // Already occupied

      this.driver = player
      player.visible = false
      player.disable_movement()
      player.attach_to(this, "driver_seat")

      // Switch controls
      Input.set_context("vehicle")

      audio.play("door_open")
      audio.start_loop("engine_idle", this)

      Camera.follow(this, { offset: [0, 5, -10] })

      return true
    }

    action exit() {
      if (!this.driver) return

      let player = this.driver
      this.driver = null

      // Find exit position
      let exit_pos = this.position + this.left * 2
      if (is_blocked(exit_pos)) {
        exit_pos = this.position + this.right * 2
      }
      if (is_blocked(exit_pos)) {
        ui.toast("Can't exit here!")
        this.driver = player
        return
      }

      player.position = exit_pos
      player.visible = true
      player.enable_movement()
      player.detach()

      Input.set_context("player")

      audio.stop_loop("engine_idle")
      audio.play("door_close")

      Camera.follow(player)
    }

    action update(dt) {
      if (!this.driver) return

      // Steering
      let steer = Input.get_axis("Horizontal")
      if (this.speed > 0.1) {
        this.rotation.y += steer * this.turn_speed * dt * (this.speed / this.max_speed)
      }

      // Acceleration/Braking
      if (Input.get("Accelerate")) {
        this.speed += this.acceleration * dt
        if (this.fuel > 0) {
          this.fuel -= dt * 0.1
        } else {
          this.speed *= 0.95  // Coast to stop
          ui.toast("Out of fuel!")
        }
      }

      if (Input.get("Brake")) {
        this.speed -= this.brake_power * dt
      }

      // Drag
      this.speed *= 0.99

      // Clamp
      this.speed = clamp(this.speed, -this.max_speed * 0.3, this.max_speed)

      // Move
      let forward = this.forward
      this.position += forward * this.speed * dt

      // Ground following (for cars)
      if (this.type == "car") {
        let ground = raycast_down(this.position)
        if (ground) {
          this.position.y = ground.y + this.ground_offset
          // Align to terrain slope
          this.rotation.x = lerp(this.rotation.x, ground.slope.x, 0.1)
          this.rotation.z = lerp(this.rotation.z, ground.slope.z, 0.1)
        }
      }

      // Engine sound based on speed
      let pitch = 1 + (this.speed / this.max_speed) * 0.5
      audio.set_pitch("engine_idle", pitch)
    }

    action take_damage(amount) {
      this.health -= amount

      if (this.health <= 50 && !this.smoking) {
        this.smoking = true
        spawn_particles("smoke", this.engine_position, { parent: this })
      }

      if (this.health <= 0) {
        this.explode()
      }
    }

    action explode() {
      // Eject driver
      if (this.driver) {
        let player = this.driver
        this.exit()
        player.take_damage(30)
        player.apply_force(random_direction() * 10)
      }

      // Explosion effect
      spawn_particles("explosion", this.position)
      audio.play("explosion_large")
      camera.shake(1, 0.5)

      // Damage nearby
      let nearby = get_in_radius(this.position, 5)
      for (obj in nearby) {
        if (obj.take_damage) {
          obj.take_damage(50)
        }
      }

      // Replace with wreck
      spawn("car_wreck", this.position, this.rotation)
      despawn(this)
    }
  }

  // Different vehicle types
  object "SportsCar" using "Vehicle" {
    position: [10, 0, 0]
    type: "car"
    max_speed: 50
    acceleration: 15
    model: "sports_car"
    seats: 2
  }

  object "Truck" using "Vehicle" {
    position: [20, 0, 0]
    type: "car"
    max_speed: 25
    acceleration: 5
    health: 200
    model: "pickup_truck"
    seats: 2
  }

  object "Motorcycle" using "Vehicle" {
    position: [30, 0, 0]
    type: "bike"
    max_speed: 60
    acceleration: 20
    turn_speed: 120
    health: 50
    model: "motorcycle"
    seats: 1
  }

  logic {
    // Enter vehicle on interact
    on_interact(vehicle) where vehicle is Vehicle {
      if (!vehicle.driver) {
        vehicle.enter(Player)
      }
    }

    // Exit on E key while in vehicle
    on_key("E") where Player.in_vehicle {
      Player.current_vehicle.exit()
    }

    // Update all vehicles
    every(16) {  // ~60fps
      for (vehicle in Vehicles) {
        vehicle.update(0.016)
      }
    }

    // Collision damage
    on_collision(vehicle, other) where vehicle is Vehicle {
      let impact = vehicle.speed * vehicle.mass
      if (impact > 10) {
        vehicle.take_damage(impact * 0.5)
        audio.play("crash")
        camera.shake(0.3, 0.2)

        if (other.take_damage) {
          other.take_damage(impact)
        }
      }
    }

    // Fuel stations
    on_interact("FuelPump") where Player.in_vehicle {
      let vehicle = Player.current_vehicle
      let cost = (100 - vehicle.fuel) * 0.5  // $0.50 per unit

      if (Player.gold >= cost) {
        Player.gold -= cost
        vehicle.fuel = 100
        audio.play("fuel_pump")
        ui.toast("Refueled! -$" + cost)
      } else {
        ui.toast("Not enough money!")
      }
    }
  }
}
