```hsplus
// inventory-system.hsplus - How inventory works
import { items } from "./items.holo";
import { clamp } from "@holoscript/std";

interface InventorySlot {
  item: Item | null;
  quantity: number;
}

export system InventoryManager {
  private slots: InventorySlot[] = [];
  private maxSlots: number = 30;
  private weight: number = 0;
  private maxWeight: number = 100;

  addItem(itemId: string, quantity: number = 1): boolean {
    const item = items.get(itemId);
    if (!item) return false;

    // Weight check
    const newWeight = this.weight + (item.weight * quantity);
    if (newWeight > this.maxWeight) {
      UI.toast("Too heavy!");
      return false;
    }

    // Stackable items
    if (item.stackable) {
      const existing = this.slots.find(s => s.item?.id === itemId);
      if (existing) {
        existing.quantity = Math.min(
          existing.quantity + quantity,
          item.max_stack
        );
        this.weight = newWeight;
        return true;
      }
    }

    // Find empty slot
    const empty = this.slots.findIndex(s => s.item === null);
    if (empty === -1) {
      UI.toast("Inventory full!");
      return false;
    }

    this.slots[empty] = { item, quantity };
    this.weight = newWeight;
    return true;
  }

  useItem(slotIndex: number): void {
    const slot = this.slots[slotIndex];
    if (!slot?.item) return;

    // Complex use logic
    switch (slot.item.effect) {
      case "heal":
        Player.health = clamp(Player.health + slot.item.value, 0, Player.maxHealth);
        break;
      case "mana":
        Player.mana = clamp(Player.mana + slot.item.value, 0, Player.maxMana);
        break;
      // ... more cases
    }

    slot.quantity--;
    if (slot.quantity <= 0) {
      this.slots[slotIndex] = { item: null, quantity: 0 };
    }
  }
}
```

