```

**.hsplus - Runtime error handling:**
```hsplus
// Full try/catch, error propagation, custom errors
import { Result, Ok, Err } from "@holoscript/std";

export system GameLoader {

  async loadWorld(path: string): Promise<Result<World, LoadError>> {
    try {
      // File operations can fail
      const file = await fs.read(path);
      if (!file) {
        return Err(new LoadError("FILE_NOT_FOUND", path));
      }

      // Parsing can fail
      const parsed = parse(file);
      if (!parsed.valid) {
        return Err(new LoadError("PARSE_ERROR", parsed.errors));
      }

      // Asset loading can fail
      const assets = await this.loadAssets(parsed.required_assets);
      if (assets.missing.length > 0) {
        console.warn(`Missing assets: ${assets.missing.join(", ")}`);
        // Graceful degradation
        assets.missing.forEach(a => this.useDefaultAsset(a));
      }

      return Ok(new World(parsed, assets));

    } catch (e) {
      // Catch unexpected errors
      console.error("Unexpected error loading world", e);
      return Err(new LoadError("UNKNOWN", e.message));
    }
  }

  private handleError(error: LoadError): void {
    switch (error.code) {
      case "FILE_NOT_FOUND":
        UI.showError("World file not found");
        break;
      case "PARSE_ERROR":
        UI.showError("Corrupted world file");
        // Offer to load backup
        UI.prompt("Load last backup?", () => this.loadBackup());
        break;
      default:
        UI.showError("Failed to load world");
    }
  }
}

// Custom error types
class LoadError extends Error {
  constructor(
    public code: string,
    public details: unknown
  ) {
    super(`Load failed: ${code}`);
  }
}
```

**Comparison:**
```
.holo errors:                    .hsplus errors:
─────────────                    ─────────────────
✓ Caught at compile/load         ✓ Caught at runtime
✓ Usually clear messages         ✓ Custom error types  
✓ Fix before running             ✓ try/catch/finally
✗ No runtime handling            ✓ Graceful degradation
✗ All-or-nothing                 ✓ Partial recovery
```

**Best practice:**

```hsplus
// Wrap .holo loading in .hsplus error handling
async function safeLoadScene(holoPath: string): World | null {
  try {
    return await loadWorld(holoPath);
  } catch (e) {
    if (e instanceof HoloParseError) {
      console.error(`Invalid .holo file: ${e.line}:${e.column}`);
      console.error(e.message);
    }
    return null;
  }
}
```

**Rule:** .holo is fail-fast (good!). .hsplus handles the failures gracefully.

