```hsplus
// network-client.hsplus - Client-side networking
import { WebSocket, MessagePack } from "@holoscript/net";
import { config } from "./network-config.holo";

export class NetworkClient {
  private ws: WebSocket | null = null;
  private playerId: string = "";
  private entities: Map<string, NetworkedEntity> = new Map();
  private interpolationBuffer: Map<string, StateSnapshot[]> = new Map();

  async connect(serverUrl: string, token: string): Promise<boolean> {
    try {
      this.ws = new WebSocket(serverUrl);

      this.ws.on("open", () => {
        this.send("auth", { token });
      });

      this.ws.on("message", (data) => {
        const msg = MessagePack.decode(data);
        this.handleMessage(msg);
      });

      this.ws.on("close", () => {
        this.handleDisconnect();
      });

      return true;
    } catch (e) {
      console.error("Failed to connect", e);
      return false;
    }
  }

  private handleMessage(msg: NetworkMessage): void {
    switch (msg.type) {
      case "state_sync":
        this.applyStateSync(msg.entities);
        break;

      case "entity_spawn":
        this.spawnNetworkedEntity(msg.entity);
        break;

      case "entity_despawn":
        this.despawnEntity(msg.entityId);
        break;

      case "player_action":
        this.handleRemoteAction(msg);
        break;
    }
  }

  // Client-side prediction
  sendAction(action: PlayerAction): void {
    // Apply locally immediately (prediction)
    const localEntity = this.entities.get(this.playerId);
    if (localEntity) {
      localEntity.applyAction(action);
    }

    // Send to server
    this.send("player_action", {
      action_type: action.type,
      target_id: action.targetId,
      position: action.position,
      sequence: this.getNextSequence()
    });
  }

  // Interpolation for smooth remote movement
  private applyStateSync(entities: EntityState[]): void {
    for (const state of entities) {
      const entity = this.entities.get(state.id);
      if (!entity) continue;

      // Don't interpolate own player (we use prediction)
      if (state.id === this.playerId) {
        this.reconcileState(state);
        continue;
      }

      // Add to interpolation buffer
      const buffer = this.interpolationBuffer.get(state.id) ?? [];
      buffer.push({ ...state, timestamp: Date.now() });

      // Keep only last 100ms of states
      while (buffer.length > 0 && buffer[0].timestamp < Date.now() - 100) {
        buffer.shift();
      }

      this.interpolationBuffer.set(state.id, buffer);
    }
  }

  // Server reconciliation
  private reconcileState(serverState: EntityState): void {
    const localEntity = this.entities.get(this.playerId)!;

    // If server says we're too far off, snap to server state
    const diff = vec3Distance(localEntity.position, serverState.position);
    if (diff > 0.5) {
      localEntity.position = serverState.position;
      localEntity.velocity = serverState.velocity;
    }
  }

  update(dt: number): void {
    // Update interpolated entities
    for (const [id, buffer] of this.interpolationBuffer) {
      if (id === this.playerId) continue;
      if (buffer.length < 2) continue;

      const entity = this.entities.get(id);
      if (!entity) continue;

      // Interpolate between states
      const renderTime = Date.now() - 50; // 50ms delay for smoothness
      const [prev, next] = this.findSurroundingStates(buffer, renderTime);

      if (prev && next) {
        const t = (renderTime - prev.timestamp) / (next.timestamp - prev.timestamp);
        entity.position = vec3Lerp(prev.position, next.position, t);
        entity.rotation = quatSlerp(prev.rotation, next.rotation, t);
      }
    }
  }
}
```

```hsplus
// network-server.hsplus - Server-side
import { WebSocketServer, Room } from "@holoscript/server";
import { config } from "./network-config.holo";

export class GameServer {
  private rooms: Map<string, GameRoom> = new Map();
  private tickRate: number = 20;

  start(port: number): void {
    const wss = new WebSocketServer({ port });

    wss.on("connection", (ws) => {
      const client = new GameClient(ws);
      this.handleNewClient(client);
    });

    // Server tick loop
    setInterval(() => this.tick(), 1000 / this.tickRate);
  }

  private tick(): void {
    for (const room of this.rooms.values()) {
      // Update game state
      room.update(1 / this.tickRate);

      // Broadcast state to all clients
      const state = room.getState();
      room.broadcast("state_sync", { entities: state });
    }
  }

  private handleNewClient(client: GameClient): void {
    client.on("join_room", async (data) => {
      const room = this.rooms.get(data.roomId);
      if (!room) {
        client.send("error", { message: "Room not found" });
        return;
      }

      const roomConfig = config.rooms[room.type];
      if (room.players.size >= roomConfig.max_players) {
        client.send("error", { message: "Room full" });
        return;
      }

      await room.addPlayer(client);
    });

    client.on("player_action", (data) => {
      // Server validates all actions
      if (!this.validateAction(client, data)) {
        client.send("action_rejected", { sequence: data.sequence });
        return;
      }

      // Apply action on server
      const room = client.room;
      if (room) {
        room.applyAction(client.playerId, data);
      }
    });
  }

  private validateAction(client: GameClient, action: any): boolean {
    // Anti-cheat: validate movement speed
    if (action.action_type === "move") {
      const lastPos = client.lastPosition;
      const newPos = action.position;
      const distance = vec3Distance(lastPos, newPos);
      const maxSpeed = 10; // units per tick

      if (distance > maxSpeed) {
        console.warn(`Speed hack detected: ${client.playerId}`);
        return false;
      }
    }

    return true;
  }
}
```

**Summary:**
```
.holo:
├── Network configuration
├── Sync rules (what data, how often)
├── Message type definitions
├── Room configurations
└── Entity replication settings

.hsplus:
├── WebSocket connections
├── State synchronization
├── Client-side prediction
├── Server reconciliation
├── Interpolation/extrapolation
├── Anti-cheat validation
├── Room management
└── All actual networking code
```

**Rule:** Network CODE is always .hsplus. Network CONFIG can be .holo.

