// tests/holo-validation.test.hsplus
import { HoloValidator, loadWorld } from "@holoscript/core";
import { describe, it, expect } from "@holoscript/test";

describe("Scene validation", () => {

  it("validates forest.holo has required elements", async () => {
    const world = await loadWorld("./scenes/forest.holo");

    // Check structure
    expect(world.hasObject("Player_Spawn")).toBe(true);
    expect(world.hasObject("Exit_Portal")).toBe(true);
    expect(world.query("enemy").length).toBeGreaterThan(0);
  });

  it("validates all object references exist", async () => {
    const validator = new HoloValidator();
    const result = await validator.validate("./scenes/forest.holo");

    expect(result.errors).toHaveLength(0);
    expect(result.warnings).toHaveLength(0);
  });

  it("snapshot test - forest scene structure", async () => {
    const world = await loadWorld("./scenes/forest.holo");
    const structure = world.toStructure();

    // Snapshot testing - catches unintended changes
    expect(structure).toMatchSnapshot();
  });

  it("validates all assets exist", async () => {
    const world = await loadWorld("./scenes/forest.holo");
    const assets = world.getRequiredAssets();

    for (const asset of assets) {
      const exists = await assetExists(asset.path);
      expect(exists).toBe(true, `Missing asset: ${asset.path}`);
    }
  });
});
